export default function createSignatureFieldName(fieldName, role, index) {
  return `${fieldName}.${role}[${index}].signature`;
}

export function replaceBracketedText(inputString) {
  // Use regular expression to replace "[x]" with an empty string
  return inputString.replace(/\[[^\]]+\]/g, '');
}

export function getCountOfFields(arr, fieldName) {
  const elementCounts = countOccurrences(arr);
  for (const element in elementCounts) {
    if (fieldName === element) {
      return elementCounts[element];
    }
  }
}

export function countOccurrences(arr) {
  const counts = {};

  for (const element of arr) {
    // eslint-disable-next-line no-prototype-builtins
    if (!counts.hasOwnProperty(element)) {
      counts[element] = 1;
    } else {
      counts[element]++;
    }
  }

  return counts;
}

function replaceCharacterBetween(sourceString, startChar, endChar, replacementChar, replaceWith) {
  const startIndex = sourceString.indexOf(startChar);
  const endIndex = sourceString.lastIndexOf(endChar);

  if (startIndex === -1 || endIndex === -1 || startIndex >= endIndex) {
    return sourceString;
  }

  const beforeStart = sourceString.substring(0, startIndex + 1);
  const betweenCharacters = sourceString.substring(startIndex + 1, endIndex);
  const afterEnd = sourceString.substring(endIndex);

  const replacedBetween = betweenCharacters.replace(
    new RegExp(replacementChar, 'g'),
    replaceWith
  );

  return beforeStart + replaceWith + afterEnd;
}

export function findCharacterBetween(sourceString, startChar, endChar) {
  const startIndex = sourceString.indexOf(startChar);
  const endIndex = sourceString.lastIndexOf(endChar);

  if (startIndex === -1 || endIndex === -1 || startIndex >= endIndex) {
    return null; // Start or end character not found, or start comes after end
  }

  const charactersBetween = sourceString.substring(startIndex + 1, endIndex);

  return charactersBetween;
}

export const getSignatureFieldName = fieldName => {
  if (!fieldName) {
    return ['', '', 0];
  }

  const [firstPart, role] = fieldName.split('.') || [];
  const lastIndex = extractNumberFromString(role);
  return [firstPart, replaceBracketedText(role), lastIndex];
};

export function extractNumberFromString(inputString) {
  const regex = /\[(\d+)\]/;
  const match = inputString.match(regex);
  return match ? parseInt(match[1]) : 0;
}

export const getAllSgintureFields = formFieldCreationManager => {
  const fields = formFieldCreationManager['$G'] || [];
  const fieldNames = fields.map(field => field?.fieldName);
  const uniqueFieldNames = Array.from(new Set(fieldNames));

  return uniqueFieldNames.filter(field => {
    const fieldName = field || '';
    if (fieldName.split('.')[0] === 'signature') {
      return field;
    }
  });
};

export const getAllRelatedSignatureFields = (signatureFields, fieldNameRole) => {
  return signatureFields.filter(field => {
    const fieldName = field;
    const _fieldNameRole = replaceBracketedText(fieldName.split('.')[1]) || null;
    return _fieldNameRole === fieldNameRole;
  });
};




