/* eslint-disable indent */
import SignatureNameDropdown from './SignatureNameDropdown';

export function getIn(obj, key, def) {
    // If the key is not provided, return the object itself
    if (!key) {
        return obj;
    }

    // Convert key to an array if it is a string (split by dot notation)
    const path = typeof key === 'string' ? key.split('.') : key;

    // Use reduce to traverse the path
    const result = path.reduce((acc, part) => {
        // If acc is undefined or null, return the default value
        if (acc === undefined || acc === null) {
            return undefined;
        }

        // Otherwise, access the next part of the path
        return acc[part];
    }, obj);

    // If the result is undefined, return the default value
    return result === undefined ? def : result;
}

export default SignatureNameDropdown;